// ─── Decode GitHub file response ───────────────────────────────────────────
// GitHub encodes file content as base64 with line-breaks every 60 chars.
// Strip those breaks before decoding to get the raw file text.

const item = $input.first().json;

const cleanBase64 = item.content.replace(/\n/g, '');
const content    = Buffer.from(cleanBase64, 'base64').toString('utf-8');
const lines      = content.split('\n');

// Files that end with \n produce a trailing empty element — remove it
// so that line numbers in the array match the visual line numbers exactly.
const cleanLines = lines[lines.length - 1] === '' ? lines.slice(0, -1) : lines;

// Build a numbered preview string for AI agents: "1: line text"
// Agents must cite these exact numbers in their output.
const numberedPreview = cleanLines
  .map((line, idx) => `${idx + 1}: ${line}`)
  .join('\n');

return [{
  json: {
    sha:             item.sha,         // Required by GitHub API to commit updates
    lines:           cleanLines,       // Array used by Code: Apply Edits
    total_lines:     cleanLines.length,
    numbered_preview: numberedPreview  // Sent to both AI agents for reference
  }
}];

// ─── Extract run history from qa-report.md ──────────────────────────────────
// Reads the last 3 QA runs from the report file and summarises which lines
// were already fixed. This is fed to Agent 1 so it does not re-flag issues
// that were addressed in previous runs.
//
// If the report file does not exist yet (first run, or node is disabled),
// the try-catch below produces an empty string — Agent 1 gets no history.

let historySummary = '';

try {
  const reportData = $('GitHub: Get QA Report').first().json;

  if (reportData && reportData.content) {
    const cleanB64    = reportData.content.replace(/\n/g, '');
    const reportText  = Buffer.from(cleanB64, 'base64').toString('utf-8');

    // Each run block is separated by a "---" horizontal rule
    const runBlocks = reportText
      .split(/^---$/m)
      .map(b => b.trim())
      .filter(b => b.startsWith('## Run:'));

    const recentRuns = runBlocks.slice(0, 3);

    if (recentRuns.length > 0) {
      historySummary = recentRuns.map(block => {
        const dateMatch  = block.match(/## Run: (.+)/);
        const date       = dateMatch ? dateMatch[1] : 'unknown date';

        // Extract issue lines from the block (lines starting with "- **Line")
        const issueLines = block
          .split('\n')
          .filter(l => l.startsWith('- **Line') || l.startsWith('- **Lines'))
          .map(l => '    ' + l.replace(/\*\*/g, '').replace(/`/g, ''))
          .join('\n');

        return `- ${date}\n` + (issueLines || '    no issues found');
      }).join('\n');
    }
  }
} catch (e) {
  // Report file does not exist yet — this is fine on the first run
  historySummary = '';
}

return [{ json: { history_summary: historySummary } }];

