// ─── Build the qa-report.md entry for this run ───────────────────────────────
// Prepends a new run block to the top of the existing report file so that
// the most recent run is always visible first.
// The report is also read by Code: Extract Memory on the next run to build
// the change-history context for Agent 1.

const runDate     = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
const issues      = $('Agent 1: QA Analysis').first().json.output || [];
const applyResult = $('Code: Apply Edits').first().json;

const issueLines = issues.map(issue => {
  const range = issue.line_start
    ? `Lines ${issue.line_start}-${issue.line_end}`
    : `Line ${issue.line_number}`;
  return `- **${range}** \`[${issue.issue_type}]\` \`${issue.priority}\` -- ${issue.description}`;
}).join('\n');

const opsLog = (applyResult.operations_log || []).map(op => {
  const range = op.line_start === op.line_end
    ? `Line ${op.line_start}`
    : `Lines ${op.line_start}-${op.line_end}`;
  return `- \`${op.operation}\` ${range}` +
    (op.new_lines_count > 0 ? ` -> ${op.new_lines_count} line(s)` : '');
}).join('\n');

const skippedSection = applyResult.skipped_count > 0
  ? '\n### Skipped operations\n' +
    applyResult.skipped_ops
      .map(op => `- \`${op.operation}\` line ${op.line_start || op.line_number}: ${op.reason}`)
      .join('\n') + '\n'
  : '';

const newEntry =
  `## Run: ${runDate}\n` +
  `**Issues found:** ${issues.length} | **Applied:** ${applyResult.applied_count} | **Skipped:** ${applyResult.skipped_count}\n\n` +
  `### Issues detected\n${issueLines || '_none_'}\n\n` +
  `### Operations applied\n${opsLog || '_none_'}\n` +
  skippedSection +
  `\n---\n\n`;

let existingContent = '';
let reportSha       = undefined;

try {
  const reportData = $('GitHub: Get QA Report').first().json;
  if (reportData && reportData.content) {
    const cleanB64  = reportData.content.replace(/\n/g, '');
    existingContent = Buffer.from(cleanB64, 'base64').toString('utf-8');
    reportSha       = reportData.sha;
  }
} catch (e) {}

const header      = '# QA Run Log\n\n';
const prevContent = existingContent.startsWith('# QA Run Log')
  ? existingContent.slice(header.length)
  : existingContent;
const fullContent = header + newEntry + prevContent;
const contentB64  = Buffer.from(fullContent).toString('base64');

const bodyObj = { message: `AI QA: log run ${runDate}`, content: contentB64 };
if (reportSha) bodyObj.sha = reportSha;

return [{ json: { report_body: JSON.stringify(bodyObj) } }];
